import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import SkillTag from '../components/SkillTag';

export default function FacultyDashboard() {
  const { user, API } = useAuth();
  const [projects, setProjects] = useState([]);
  const [requests, setRequests] = useState([]);
  const [showCreate, setShowCreate] = useState(false);
  const [form, setForm] = useState({ title:'', description:'', requiredSkills:'', tags:'', duration:'', stipend:'', prerequisites:'' });
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  const load = async () => {
    try {
      const [pRes, rRes] = await Promise.all([
        axios.get(`${API}/projects/my`),
        axios.get(`${API}/requests/my`)
      ]);
      setProjects(pRes.data);
      setRequests(rRes.data);
    } catch {}
    setLoading(false);
  };

  useEffect(() => { load(); }, [API]);

  const handleCreate = async () => {
    try {
      await axios.post(`${API}/projects`, {
        ...form,
        requiredSkills: form.requiredSkills.split(',').map(s=>s.trim()).filter(Boolean),
        tags: form.tags.split(',').map(s=>s.trim()).filter(Boolean)
      });
      setShowCreate(false);
      setForm({ title:'', description:'', requiredSkills:'', tags:'', duration:'', stipend:'', prerequisites:'' });
      load();
    } catch (err) { alert(err.response?.data?.message || 'Failed'); }
  };

  const handleRequest = async (reqId, status, note) => {
    try {
      await axios.put(`${API}/requests/${reqId}`, { status, facultyNote: note });
      load();
    } catch (err) { alert(err.response?.data?.message || 'Failed'); }
  };

  const stats = [
    { label: 'My Projects', value: projects.length, icon: '🗂', color: '#6c63ff' },
    { label: 'Pending Requests', value: requests.filter(r=>r.status==='pending').length, icon: '📬', color: '#ffb347' },
    { label: 'Accepted Students', value: requests.filter(r=>r.status==='accepted').length, icon: '✅', color: '#4ade80' },
    { label: 'Total Applicants', value: requests.length, icon: '👥', color: '#00d4aa' },
  ];

  if (loading) return <div style={{padding:'3rem',textAlign:'center',color:'#6c63ff'}}>Loading...</div>;

  return (
    <div style={{padding:'2rem',maxWidth:1200,margin:'0 auto'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:'2rem'}}>
        <div>
          <h1 style={{fontWeight:800,fontSize:'1.75rem',marginBottom:'0.25rem'}}>Faculty Dashboard</h1>
          <p style={{color:'#9aa3bf'}}>{user.department} · {user.designation}</p>
        </div>
        <button onClick={()=>setShowCreate(true)} style={{padding:'10px 20px',background:'linear-gradient(135deg, #6c63ff, #8b85ff)',border:'none',borderRadius:10,color:'#fff',fontWeight:700,cursor:'pointer',fontSize:'0.9rem'}}>
          + Create Project
        </button>
      </div>

      <div style={{display:'grid',gridTemplateColumns:'repeat(4, 1fr)',gap:'1rem',marginBottom:'2rem'}}>
        {stats.map((s, i) => (
          <div key={i} style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:14,padding:'1.25rem'}}>
            <div style={{fontSize:'1.5rem',marginBottom:'0.5rem'}}>{s.icon}</div>
            <div style={{fontSize:'2rem',fontWeight:800,color:s.color,fontFamily:'Space Mono, monospace'}}>{s.value}</div>
            <div style={{color:'#9aa3bf',fontSize:'0.875rem',marginTop:'0.25rem'}}>{s.label}</div>
          </div>
        ))}
      </div>

      <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:'2rem'}}>
        <div>
          <h2 style={{fontWeight:700,fontSize:'1.1rem',marginBottom:'1rem'}}>My Projects</h2>
          {projects.length === 0 ? (
            <div style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:14,padding:'2rem',textAlign:'center',color:'#5c6580'}}>
              <div style={{fontSize:'2rem',marginBottom:'0.5rem'}}>📋</div>
              <div>No projects yet</div>
            </div>
          ) : projects.map(p => (
            <div key={p._id} style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:14,padding:'1.25rem',marginBottom:'1rem'}}>
              <div style={{display:'flex',justifyContent:'space-between',marginBottom:'0.5rem'}}>
                <Link to={`/projects/${p._id}`} style={{fontWeight:700,color:'#e8eaf0',textDecoration:'none'}}>{p.title}</Link>
                <span style={{background:p.status==='open'?'rgba(0,212,170,0.15)':'rgba(255,87,87,0.15)',color:p.status==='open'?'#00d4aa':'#ff5757',border:`1px solid ${p.status==='open'?'#00d4aa40':'#ff575740'}`,borderRadius:99,padding:'2px 10px',fontSize:'0.75rem',fontWeight:600}}>
                  {p.status}
                </span>
              </div>
              <p style={{color:'#9aa3bf',fontSize:'0.8rem',marginBottom:'0.75rem'}}>{p.description?.substring(0,100)}...</p>
              <div style={{display:'flex',gap:'0.4rem',flexWrap:'wrap',marginBottom:'0.75rem'}}>
                {p.requiredSkills?.slice(0,3).map(s=><SkillTag key={s} skill={s} />)}
              </div>
              <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:'8px 12px',background:'#0f1320',borderRadius:8}}>
                <span style={{fontSize:'0.8rem',color:'#9aa3bf'}}>Students</span>
                <span style={{fontFamily:'Space Mono, monospace',fontSize:'0.8rem',color:'#6c63ff',fontWeight:700}}>{p.acceptedStudents?.length || 0}/{p.maxStudents}</span>
              </div>
            </div>
          ))}
        </div>

        <div>
          <h2 style={{fontWeight:700,fontSize:'1.1rem',marginBottom:'1rem'}}>Pending Requests</h2>
          {requests.filter(r=>r.status==='pending').length === 0 ? (
            <div style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:14,padding:'2rem',textAlign:'center',color:'#5c6580'}}>
              <div style={{fontSize:'2rem',marginBottom:'0.5rem'}}>📭</div>
              <div>No pending requests</div>
            </div>
          ) : requests.filter(r=>r.status==='pending').map(r => (
            <div key={r._id} style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:14,padding:'1.25rem',marginBottom:'1rem'}}>
              <div style={{display:'flex',justifyContent:'space-between',marginBottom:'0.5rem'}}>
                <div style={{fontWeight:700,color:'#e8eaf0'}}>{r.student?.name}</div>
                <span style={{fontFamily:'Space Mono',fontSize:'0.8rem',color:r.skillMatchScore>=70?'#4ade80':r.skillMatchScore>=40?'#ffb347':'#ff5757',fontWeight:700}}>{r.skillMatchScore}% match</span>
              </div>
              <div style={{fontSize:'0.8rem',color:'#9aa3bf',marginBottom:'0.25rem'}}>{r.student?.department} · {r.student?.year} · GPA: {r.student?.gpa || 'N/A'}</div>
              <div style={{fontSize:'0.8rem',color:'#6c63ff',marginBottom:'0.75rem'}}>For: {r.project?.title}</div>
              <div style={{display:'flex',gap:'0.4rem',flexWrap:'wrap',marginBottom:'0.75rem'}}>
                {r.student?.skills?.slice(0,4).map(s=><SkillTag key={s} skill={s} />)}
              </div>
              <p style={{fontSize:'0.8rem',color:'#9aa3bf',marginBottom:'0.75rem',fontStyle:'italic'}}>"{r.message?.substring(0,100)}..."</p>
              <div style={{display:'flex',gap:'0.5rem'}}>
                <button onClick={()=>handleRequest(r._id,'accepted','')} style={{flex:1,padding:'8px',background:'rgba(74,222,128,0.1)',border:'1px solid #4ade8040',borderRadius:8,color:'#4ade80',fontWeight:600,cursor:'pointer',fontSize:'0.8rem'}}>✓ Accept</button>
                <button onClick={()=>handleRequest(r._id,'rejected','')} style={{flex:1,padding:'8px',background:'rgba(255,87,87,0.1)',border:'1px solid #ff575740',borderRadius:8,color:'#ff5757',fontWeight:600,cursor:'pointer',fontSize:'0.8rem'}}>✗ Reject</button>
                <Link to={`/students`} style={{padding:'8px 12px',background:'rgba(108,99,255,0.1)',border:'1px solid #6c63ff40',borderRadius:8,color:'#6c63ff',fontWeight:600,cursor:'pointer',fontSize:'0.8rem',textDecoration:'none',display:'flex',alignItems:'center'}}>Profile</Link>
              </div>
            </div>
          ))}
        </div>
      </div>

      {showCreate && (
        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.7)',display:'flex',alignItems:'center',justifyContent:'center',zIndex:1000,padding:'1rem'}}>
          <div style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:16,padding:'2rem',width:'100%',maxWidth:560,maxHeight:'90vh',overflowY:'auto'}}>
            <h2 style={{fontWeight:800,marginBottom:'1.5rem'}}>Create New Project</h2>
            {[
              {label:'Project Title',key:'title',placeholder:'e.g. AI Campus Assistant'},
              {label:'Description',key:'description',placeholder:'Describe the project goals and scope...',multi:true},
              {label:'Required Skills (comma separated)',key:'requiredSkills',placeholder:'Python, Machine Learning, TensorFlow'},
              {label:'Tags (comma separated)',key:'tags',placeholder:'AI, NLP, Research'},
              {label:'Duration (optional)',key:'duration',placeholder:'e.g. 6 months'},
              {label:'Stipend (optional)',key:'stipend',placeholder:'e.g. ₹10,000/month or Unpaid'},
              {label:'Prerequisites (optional)',key:'prerequisites',placeholder:'e.g. CGPA > 8.0, prior ML knowledge'},
            ].map(f => (
              <div key={f.key} style={{marginBottom:'1rem'}}>
                <label style={{display:'block',marginBottom:'6px',fontSize:'0.875rem',fontWeight:600,color:'#9aa3bf'}}>{f.label}</label>
                {f.multi
                  ? <textarea value={form[f.key]} onChange={e=>setForm(x=>({...x,[f.key]:e.target.value}))} placeholder={f.placeholder} rows={3} style={{width:'100%',padding:'10px 14px',background:'#0f1320',border:'1px solid #252d47',borderRadius:8,color:'#e8eaf0',fontSize:'0.9rem',outline:'none',resize:'vertical'}} />
                  : <input value={form[f.key]} onChange={e=>setForm(x=>({...x,[f.key]:e.target.value}))} placeholder={f.placeholder} style={{width:'100%',padding:'10px 14px',background:'#0f1320',border:'1px solid #252d47',borderRadius:8,color:'#e8eaf0',fontSize:'0.9rem',outline:'none'}} />
                }
              </div>
            ))}
            <div style={{display:'flex',gap:'0.75rem'}}>
              <button onClick={()=>setShowCreate(false)} style={{flex:1,padding:'12px',background:'transparent',border:'1px solid #252d47',borderRadius:10,color:'#9aa3bf',fontWeight:600,cursor:'pointer'}}>Cancel</button>
              <button onClick={handleCreate} style={{flex:2,padding:'12px',background:'linear-gradient(135deg, #6c63ff, #8b85ff)',border:'none',borderRadius:10,color:'#fff',fontWeight:700,cursor:'pointer'}}>Create Project</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
